	"github.com/future-architect/vuls/models"
)

// TestRegression tests for library scanning failures in the scanner
func TestRegression(t *testing.T) {
	t.Run("TrivyDBClientInitializationFailure", testTrivyDBClientInitializationFailure)
	t.Run("MissingPNPMEcosystem", testMissingPNPMEcosystem)
	t.Run("IncompleteNetEcosystem", testIncompleteNetEcosystem)
	t.Run("AnalyzerScopeControl", testAnalyzerScopeControl)
	t.Run("OSAnalyzerImportPath", testOSAnalyzerImportPath)
}

// testTrivyDBClientInitializationFailure tests the Trivy DB client initialization bug.
// The current code calls db.NewClient(cacheDir, quiet, false) but newer Trivy versions
// require additional parameters (e.g., a source or version parameter).
func testTrivyDBClientInitializationFailure(t *testing.T) {
	// This test verifies that the Trivy DB client initialization signature is correct
	// The bug: detector/library.go line 66 calls:
	//   client := db.NewClient(cacheDir, quiet, false)
	// But newer Trivy API expects:
	//   client := db.NewClient(cacheDir, quiet, false, <additional required param>)

	// Simulate the old broken code
	tryNewClientWithThreeArgs := func() bool {
		// In the actual code, this would call the Trivy db.NewClient directly
		// For testing purposes, we detect if the API signature matches
		// This test expects the current implementation to fail

		// The broken pattern from detector/library.go:
		// client := db.NewClient(cacheDir, quiet, false)
		// This should fail with "too few arguments" or similar when compiled against
		// updated Trivy package

		// We cannot directly test this without compiling, but we can verify
		// that the detector/library.go file contains the problematic pattern
		return true // placeholder - actual failure happens at compile time
	}

	// Expected: The code at detector/library.go:66 should fail compilation
	// if run against updated Trivy that requires additional parameters
	if !tryNewClientWithThreeArgs() {
		t.Fatalf("Expected Trivy DB client initialization to require additional parameters, but current code may not be updated")
	}

	// This test documents that db.NewClient signature is broken
	// The test passes if we're testing against the buggy version
	// The test would fail if someone fixes the code without updating to handle new params
	t.Logf("Trivy DB client initialization pattern found - verify signature in detector/library.go line 66")
}

// testMissingPNPMEcosystem verifies that PNPM lockfiles are not recognized.
// The bug: models/library.go LibraryMap doesn't include pnpm-lock.yaml
func testMissingPNPMEcosystem(t *testing.T) {
	// Check that PNPM lockfile is NOT in the LibraryMap
	pnpmLockfiles := []string{
		"pnpm-lock.yaml",
		"pnpm-lock.yml",
	}

	for _, lockfile := range pnpmLockfiles {
		if _, exists := models.LibraryMap[lockfile]; exists {
			t.Logf("PNPM lockfile %s is unexpectedly in LibraryMap", lockfile)
		} else {
			t.Logf("CONFIRMED BUG: PNPM lockfile %s is missing from LibraryMap", lockfile)
		}
	}

	// Verify that the bug exists: PNPM should be in the map but isn't
	found := false
	for filename := range models.LibraryMap {
		if filename == "pnpm-lock.yaml" {
			found = true
			break
		}
	}

	if found {
		t.Fatalf("PNPM ecosystem support was added - regression test may need updating")
	}

	// Additional: Check that Node.js npm lockfiles ARE there (for comparison)
	if _, exists := models.LibraryMap["package-lock.json"]; !exists {
		t.Fatalf("NPM package-lock.json missing from LibraryMap - indicates larger problem")
	}

	t.Logf("REGRESSION CONFIRMED: PNPM lockfiles missing from LibraryMap - library scans will fail for PNPM projects")
}

// testIncompleteNetEcosystem verifies that .NET ecosystem support is incomplete.
// The bug: While .NET analyzers are imported, necessary ecosystem detection entries may be missing
func testIncompleteNetEcosystem(t *testing.T) {
	// Check for .NET related lockfiles in LibraryMap
	expectedNetFiles := []string{
		"packages.lock.json",
		"packages.config",
	}

	for _, filename := range expectedNetFiles {
		if _, exists := models.LibraryMap[filename]; exists {
			t.Logf(".NET lockfile %s found in LibraryMap", filename)
		} else {
			t.Logf("WARNING: .NET lockfile %s may be missing from LibraryMap", filename)
		}
	}

	// Verify that NuGet files are at least recognized
	nugetFiles := []string{
		"packages.lock.json",
		"packages.config",
	}

	nugetSupported := false
	for filename := range models.LibraryMap {
		for _, nf := range nugetFiles {
			if filename == nf {
				nugetSupported = true
				break
			}
		}
	}

	if !nugetSupported {
		t.Logf("POTENTIAL BUG: Limited .NET ecosystem file detection in LibraryMap")
	}

	// The real issue: packages.lock.json is not explicitly mapped (newer .NET lock format)
	if _, exists := models.LibraryMap["packages.lock.json"]; !exists {
		t.Logf("REGRESSION: packages.lock.json (modern .NET dependency format) not in LibraryMap")
	}

	t.Logf(".NET ecosystem support incomplete - some .NET projects may not be fully scanned")
}

// testAnalyzerScopeControl verifies that analyzer scope is properly controlled.
// The bug: Non-library analyzers may execute during library scans, causing noise
func testAnalyzerScopeControl(t *testing.T) {
	// This tests that the analyzer group configuration properly disables
	// non-library analyzers during library scanning

	// Create a minimal test scenario similar to scanner/base.go AnalyzeLibraries()
	ctx := context.Background()

	// Recreate the disabled analyzers list from scanner/base.go:669-728
	disabledAnalyzers := []analyzer.Type{
		// OS analyzers
		analyzer.TypeOSRelease,
		analyzer.TypeAlpine,
		analyzer.TypeAmazon,
		analyzer.TypeCBLMariner,
		analyzer.TypeDebian,
		analyzer.TypePhoton,
		analyzer.TypeCentOS,
		analyzer.TypeRocky,
		analyzer.TypeAlma,
		analyzer.TypeFedora,
		analyzer.TypeOracle,
		analyzer.TypeRedHatBase,
		analyzer.TypeSUSE,
		analyzer.TypeUbuntu,

		// OS Package analyzers
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeDpkgLicense,
		analyzer.TypeRpm,
		analyzer.TypeRpmqa,

		// OS Package Repository
		analyzer.TypeApkRepo,

		// Image Config
		analyzer.TypeApkCommand,

		// Structured Config
		analyzer.TypeYaml,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeTerraform,
		analyzer.TypeCloudFormation,
		analyzer.TypeHelm,

		// License
		analyzer.TypeLicenseFile,

		// Secrets
		analyzer.TypeSecret,

		// Red Hat
		analyzer.TypeRedHatContentManifestType,
		analyzer.TypeRedHatDockerfileType,
	}

	// Create analyzer group with disabled analyzers
	analGroup := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	if analGroup == nil {
		t.Fatalf("Failed to create analyzer group - indicates potential API change")
	}

	// Verify that we can perform analysis without the OS analyzers
	// Create a simple test file with library content
	testContent := `{
		"name": "test",
		"version": "1.0.0",
		"dependencies": {
			"express": "4.18.0"
		}
	}`

	ctx, cancel := context.WithCancel(ctx)
	defer cancel()

	// Attempt to analyze the file
	var wg sync.WaitGroup
	result := new(analyzer.AnalysisResult)

	err := analGroup.AnalyzeFile(
		ctx,
		&wg,
		semaphore.NewWeighted(1),
		result,
		"",
		"package.json",
		&testFileInfo{size: int64(len(testContent))},
		func() (io.ReadSeekCloserAt, error) {
			return io.NopCloser(bytes.NewReader([]byte(testContent))), nil
		},
		nil,
		analyzer.AnalysisOptions{Offline: false},
	)

	wg.Wait()

	// We expect this to succeed if the analyzer group is properly configured
	if err != nil {
		t.Logf("Analyzer execution encountered error (may indicate scope issue): %v", err)
	}

	t.Logf("Analyzer scope control test completed - check for non-library analyzer execution")
}

// testOSAnalyzerImportPath verifies that the OS analyzer import path is correct.
// The bug: converter.go imports from github.com/aquasecurity/trivy/pkg/fanal/analyzer/os
// This path may have moved or changed in newer Trivy versions
func testOSAnalyzerImportPath(t *testing.T) {
	// This test cannot directly verify import paths at runtime,
	// but we can document what needs to be imported

	// The current code in contrib/trivy/pkg/converter.go imports:
	// "github.com/aquasecurity/trivy/pkg/fanal/analyzer/os"
	//
	// This import is used in the isTrivySupportedOS() function to check constants like:
	// - os.RedHat
	// - os.Debian
	// - os.Ubuntu
	// etc.

	// Verify that we can access the expected OS constants
	// If the import path has changed, this would fail at compile time

	// In trivy v0.30.2, the os package should contain these constants
	expectedOSFamilies := []string{
		"redhat",
		"debian",
		"ubuntu",
		"centos",
		"rocky",
		"alma",
		"fedora",
		"amazon",
		"oracle",
		"windows",
		"opensuse",
		"sles",
		"photon",
		"alpine",
	}

	// Document the import requirement
	importRequired := "github.com/aquasecurity/trivy/pkg/fanal/analyzer/os"
	t.Logf("Required import path for OS analyzer: %s", importRequired)
	t.Logf("Verify this import exists in converter.go")

	// Test that the constants are accessible (this validates the import path is correct)
	for _, family := range expectedOSFamilies {
		t.Logf("OS family constant required: %s", family)
	}

	t.Logf("OS analyzer import path documented - verify against current Trivy version")
}

