// testLibraryScannerIntegration tests the library scanning scenarios
func testLibraryScannerIntegration(t *testing.T) {
	tests := []struct {
		name         string
		lockfile     string
		shouldExist  bool
		reason       string
	}{
		{
			name:        "npm_supported",
			lockfile:    "package-lock.json",
			shouldExist: true,
			reason:      "npm lockfile should be supported",
		},
		{
			name:        "pnpm_missing",
			lockfile:    "pnpm-lock.yaml",
			shouldExist: false,
			reason:      "REGRESSION BUG: PNPM lockfiles missing - causes zero findings in PNPM projects",
		},
		{
			name:        "yarn_supported",
			lockfile:    "yarn.lock",
			shouldExist: true,
			reason:      "yarn lockfile should be supported",
		},
		{
			name:        "go_supported",
			lockfile:    "go.mod",
			shouldExist: true,
			reason:      "Go module lockfile should be supported",
		},
		{
			name:        "dotnet_packages_lock",
			lockfile:    "packages.lock.json",
			shouldExist: false,
			reason:      "REGRESSION BUG: packages.lock.json missing - modern .NET projects not fully scanned",
		},
		{
			name:        "python_poetry_supported",
			lockfile:    "poetry.lock",
			shouldExist: true,
			reason:      "Poetry lockfile should be supported",
		},
	}

	regressionCount := 0
	for _, tt := range tests {
		_, exists := models.LibraryMap[tt.lockfile]

		if exists != tt.shouldExist {
			t.Logf("MISMATCH %s: %s expected=%v actual=%v", tt.name, tt.lockfile, tt.shouldExist, exists)
			if !tt.shouldExist && exists {
				t.Logf("  Unexpected: Bug appears to be fixed")
			} else if tt.shouldExist && !exists {
				t.Logf("  Missing: %s", tt.reason)
				regressionCount++
			}
		} else if !tt.shouldExist && !exists {
			t.Logf("CONFIRMED BUG %s: %s - %s", tt.name, tt.lockfile, tt.reason)
			regressionCount++
		}
	}

	t.Logf("Regression test results: %d issues confirmed", regressionCount)
	if regressionCount > 0 {
		t.Logf("Library scanning has %d documented regressions", regressionCount)
	}
}

