		analyzer.TypeAmazon,
		analyzer.TypeCBLMariner,
		analyzer.TypeDebian,
		analyzer.TypePhoton,
		analyzer.TypeCentOS,
		analyzer.TypeRocky,
		analyzer.TypeAlma,
		analyzer.TypeFedora,
		analyzer.TypeOracle,
		analyzer.TypeRedHatBase,
		analyzer.TypeSUSE,
		analyzer.TypeUbuntu,

		// OS Package analyzers
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeDpkgLicense,
		analyzer.TypeRpm,
		analyzer.TypeRpmqa,

		// OS Package Repository
		analyzer.TypeApkRepo,

		// Image Config
		analyzer.TypeApkCommand,

		// Structured Config
