// testLibraryScannerIntegration tests the library scanning scenarios
func testLibraryScannerIntegration(t *testing.T) {
	tests := []struct {
		name         string
		lockfile     string
		shouldExist  bool
		reason       string
	}{
		{
			name:        "npm_supported",
			lockfile:    "package-lock.json",
			shouldExist: true,
			reason:      "npm lockfile should be supported",
		},
		{
			name:        "pnpm_missing",
			lockfile:    "pnpm-lock.yaml",
			shouldExist: false,
			reason:      "REGRESSION BUG: PNPM lockfiles missing - causes zero findings in PNPM projects",
		},
		{
			name:        "yarn_supported",
			lockfile:    "yarn.lock",
			shouldExist: true,
			reason:      "yarn lockfile should be supported",
		},
		{
			name:        "go_supported",
			lockfile:    "go.mod",
			shouldExist: true,
			reason:      "Go module lockfile should be supported",
		},
		{
			name:        "dotnet_packages_lock",
			lockfile:    "packages.lock.json",
			shouldExist: false,
			reason:      "REGRESSION BUG: packages.lock.json missing - modern .NET projects not fully scanned",
		},
		{
			name:        "python_poetry_supported",
			lockfile:    "poetry.lock",
			shouldExist: true,
			reason:      "Poetry lockfile should be supported",
		},
	}

	regressionCount := 0
	for _, tt := range tests {
		_, exists := models.LibraryMap[tt.lockfile]

		if exists != tt.shouldExist {
			t.Logf("MISMATCH %s: %s expected=%v actual=%v", tt.name, tt.lockfile, tt.shouldExist, exists)
			if !tt.shouldExist && exists {
				t.Logf("  Unexpected: Bug appears to be fixed")
			} else if tt.shouldExist && !exists {
				t.Logf("  Missing: %s", tt.reason)
				regressionCount++
			}
		} else if !tt.shouldExist && !exists {
			t.Logf("CONFIRMED BUG %s: %s - %s", tt.name, tt.lockfile, tt.reason)
			regressionCount++
		}
	}

	t.Logf("Regression test results: %d issues confirmed", regressionCount)
	if regressionCount > 0 {
		t.Logf("Library scanning has %d documented regressions", regressionCount)
	}
}

package models

import (
	"path/filepath"

	"github.com/aquasecurity/trivy-db/pkg/db"
	trivyDBTypes "github.com/aquasecurity/trivy-db/pkg/types"
	"github.com/aquasecurity/trivy/pkg/detector/library"
	ftypes "github.com/aquasecurity/trivy/pkg/fanal/types"
	"github.com/aquasecurity/trivy/pkg/types"
	"golang.org/x/xerrors"

	"github.com/future-architect/vuls/logging"
)

// LibraryScanners is an array of LibraryScanner
type LibraryScanners []LibraryScanner

// Find : find by name
func (lss LibraryScanners) Find(path, name string) map[string]Library {
	filtered := map[string]Library{}
	for _, ls := range lss {
		for _, lib := range ls.Libs {
			if ls.LockfilePath == path && lib.Name == name {
				filtered[ls.LockfilePath] = lib
				break
			}
		}
	}
	return filtered
}

// Total returns total count of pkgs
func (lss LibraryScanners) Total() (total int) {
	for _, lib := range lss {
		total += len(lib.Libs)
	}
	return
}

// LibraryScanner has libraries information
type LibraryScanner struct {
	Type string
	Libs []Library

	// The path to the Lockfile is stored.
	LockfilePath string `json:"path,omitempty"`
}

// Library holds the attribute of a package library
type Library struct {
	Name    string
	Version string

	// The Path to the library in the container image. Empty string when Lockfile scan.
	// This field is used to convert the result JSON of a `trivy image` using trivy-to-vuls.
	FilePath string
}

// Scan : scan target library
func (s LibraryScanner) Scan() ([]VulnInfo, error) {
	scanner, err := library.NewDriver(s.Type)
	if err != nil {
		return nil, xerrors.Errorf("Failed to new a library driver %s: %w", s.Type, err)
	}
	var vulnerabilities = []VulnInfo{}
	for _, pkg := range s.Libs {
		tvulns, err := scanner.DetectVulnerabilities("", pkg.Name, pkg.Version)
		if err != nil {
			return nil, xerrors.Errorf("failed to detect %s vulnerabilities: %w", scanner.Type(), err)
		}
		if len(tvulns) == 0 {
			continue
		}

		vulns := s.convertFanalToVuln(tvulns)
		vulnerabilities = append(vulnerabilities, vulns...)
	}

	return vulnerabilities, nil
}

func (s LibraryScanner) convertFanalToVuln(tvulns []types.DetectedVulnerability) (vulns []VulnInfo) {
	for _, tvuln := range tvulns {
		vinfo, err := s.getVulnDetail(tvuln)
		if err != nil {
			logging.Log.Debugf("failed to getVulnDetail. err: %+v, tvuln: %#v", err, tvuln)
			continue
		}
		vulns = append(vulns, vinfo)
	}
	return vulns
}

func (s LibraryScanner) getVulnDetail(tvuln types.DetectedVulnerability) (vinfo VulnInfo, err error) {
	vul, err := db.Config{}.GetVulnerability(tvuln.VulnerabilityID)
	if err != nil {
		return vinfo, err
	}

	vinfo.CveID = tvuln.VulnerabilityID
	vinfo.CveContents = getCveContents(tvuln.VulnerabilityID, vul)
	vinfo.LibraryFixedIns = []LibraryFixedIn{
		{
			Key:     s.GetLibraryKey(),
			Name:    tvuln.PkgName,
			FixedIn: tvuln.FixedVersion,
			Path:    s.LockfilePath,
		},
	}
	return vinfo, nil
}

func getCveContents(cveID string, vul trivyDBTypes.Vulnerability) (contents map[CveContentType][]CveContent) {
	contents = map[CveContentType][]CveContent{}
	refs := []Reference{}
	for _, refURL := range vul.References {
		refs = append(refs, Reference{Source: "trivy", Link: refURL})
	}

	contents[Trivy] = []CveContent{
		{
			Type:          Trivy,
			CveID:         cveID,
			Title:         vul.Title,
			Summary:       vul.Description,
			Cvss3Severity: string(vul.Severity),
			References:    refs,
		},
	}
	return contents
}

// LibraryMap is filename and library type
var LibraryMap = map[string]string{
	ftypes.NpmPkgLock:      "node",
	ftypes.YarnLock:        "node",
	ftypes.GemfileLock:     "ruby",
	ftypes.CargoLock:       "rust",
	ftypes.ComposerLock:    "php",
	ftypes.PipRequirements: "python",
	ftypes.PipfileLock:     "python",
	ftypes.PoetryLock:      "python",
	ftypes.NuGetPkgsLock:   ".net",
	ftypes.NuGetPkgsConfig: ".net",
	ftypes.GoMod:           "gomod",
	ftypes.GoSum:           "gomod",
	ftypes.MavenPom:        "java",
	"*.jar":                "java",
	"*.war":                "java",
	"*.ear":                "java",
	"*.par":                "java",
}

// GetLibraryKey returns target library key
func (s LibraryScanner) GetLibraryKey() string {
	switch s.Type {
	case ftypes.Bundler, ftypes.GemSpec:
		return "ruby"
	case ftypes.Cargo:
		return "rust"
	case ftypes.Composer:
		return "php"
	case ftypes.GoBinary, ftypes.GoModule:
		return "gomod"
	case ftypes.Jar, ftypes.Pom:
		return "java"
	case ftypes.Npm, ftypes.Yarn, ftypes.NodePkg, ftypes.JavaScript:
		return "node"
	case ftypes.NuGet:
		return ".net"
	case ftypes.Pipenv, ftypes.Poetry, ftypes.Pip, ftypes.PythonPkg:
		return "python"
	default:
		filename := filepath.Base(s.LockfilePath)
		switch filepath.Ext(filename) {
		case ".jar", ".war", ".ear", ".par":
			return "java"
		default:
			return LibraryMap[filename]
		}
	}
}

// LibraryFixedIn has library fixed information
type LibraryFixedIn struct {
	Key     string `json:"key,omitempty"`
	Name    string `json:"name,omitempty"`
	FixedIn string `json:"fixedIn,omitempty"`
	Path    string `json:"path,omitempty"`
}

